INSERT INTO contract_templates (contract_type, jurisdiction, version, title, preamble, recitals, clauses, signature_block, placeholders, is_active, metadata) VALUES (
  'consulting_agreement',
  'us_texas',
  1,
  'Consulting Services Agreement (Texas)',
  'This Consulting Services Agreement (the "Agreement") is entered into as of {{effective_date}} (the "Effective Date"), by and between {{party_a_company}}, with an address at {{party_a_address}} ("Client"), and {{party_b_company}}, with an address at {{party_b_address}} ("Consultant").',
  'WHEREAS, Client desires to engage Consultant to provide professional consulting services as described herein;
WHEREAS, Consultant has the expertise and qualifications to provide such services;
NOW, THEREFORE, in consideration of the mutual covenants contained herein, the Parties agree as follows:',
  '[{"id":"engagement","title":"1. ENGAGEMENT AND SERVICES","content":"1.1 Engagement. Client hereby engages Consultant, and Consultant hereby accepts such engagement, to provide the consulting services described in {{services_description}} (the \"Services\").\n\n1.2 Standard of Performance. Consultant shall perform the Services in a professional and workmanlike manner, in accordance with generally accepted industry standards, and in compliance with all applicable laws.\n\n1.3 Deliverables. Consultant shall deliver any deliverables specified in {{services_description}} in accordance with the timeline and specifications set forth therein.\n\n1.4 Client Cooperation. Client shall provide Consultant with reasonable access to personnel, information, and resources necessary for Consultant to perform the Services.\n\n1.5 Changes. Any changes to the Services must be agreed in writing by both Parties.","type":"standard","order":1},{"id":"fees_payment","title":"2. FEES AND PAYMENT","content":"2.1 Fees. Client shall pay Consultant the fees set forth in {{services_description}}, which may include: (a) a fixed fee of {{payment_amount}}; and/or (b) an hourly rate of {{hourly_rate}}.\n\n2.2 Invoicing. Consultant shall submit invoices in accordance with {{services_description}}, or monthly in arrears if not specified.\n\n2.3 Payment Terms. Client shall pay undisputed invoices within 30 days of receipt. Late payments shall accrue interest at 1.5% per month or the maximum rate permitted by Texas law, whichever is less.\n\n2.4 Expenses. Unless pre-approved in writing by Client, Consultant shall bear all expenses.\n\n2.5 Taxes. Consultant is responsible for all taxes arising from fees received. Texas does not impose a state income tax on individuals. Client will not withhold payroll taxes for Consultant.","type":"standard","order":2},{"id":"consultant_status","title":"3. CONSULTANT STATUS","content":"3.1 Independent Contractor. Consultant is an independent contractor and not an employee, worker, agent, or partner of Client.\n\n3.2 Control. Consultant shall determine the manner and means of performing the Services, subject to the requirements of this Agreement.\n\n3.3 Texas Classification. The Parties intend that Consultant be properly classified as an independent contractor under Texas law, including Texas Labor Code and Texas Workforce Commission guidelines.\n\n3.4 No Employee Benefits. Consultant is not entitled to Client''s employee benefits.\n\n3.5 Other Engagements. Consultant may provide services to other clients, provided this does not conflict with obligations under this Agreement.","type":"standard","order":3},{"id":"term_termination","title":"4. TERM AND TERMINATION","content":"4.1 Term. This Agreement commences on the Effective Date and continues until {{expiration_date}}, or if not specified, until the Services are completed, unless earlier terminated.\n\n4.2 Termination for Convenience. Either Party may terminate by giving {{notice_period}} days'' written notice.\n\n4.3 Termination for Cause. Either Party may terminate immediately if the other Party: (a) materially breaches and fails to cure within 10 days of notice; (b) becomes insolvent; or (c) commits fraud or gross misconduct.\n\n4.4 Effect of Termination. Upon termination: (a) Consultant shall cease Services and deliver all Work Product; (b) Client shall pay for Services properly performed through termination.\n\n4.5 Survival. Provisions intended to survive shall survive termination.","type":"standard","order":4},{"id":"intellectual_property","title":"5. INTELLECTUAL PROPERTY","content":"5.1 Work Product. \"Work Product\" means all materials, deliverables, and works created by Consultant in performing the Services.\n\n5.2 Assignment. Consultant assigns to Client all rights in the Work Product, including all intellectual property rights.\n\n5.3 Background IP. Consultant retains pre-existing intellectual property (\"Background IP\"). If Background IP is incorporated into Work Product, Consultant grants Client a perpetual, royalty-free, sublicensable license to use such Background IP.\n\n5.4 Moral Rights. Consultant waives moral rights in the Work Product to the extent permitted by law.\n\n5.5 Third Party Materials. Consultant shall not incorporate third-party materials without appropriate licenses and Client approval.","type":"negotiable","order":5},{"id":"confidentiality","title":"6. CONFIDENTIALITY","content":"6.1 Confidential Information. \"Confidential Information\" means all non-public information disclosed by one Party to the other that is designated confidential or should reasonably be understood to be confidential. This includes Trade Secrets under the Texas Uniform Trade Secrets Act.\n\n6.2 Obligations. Each Party shall: (a) use Confidential Information only for this Agreement; (b) protect it with reasonable care; (c) disclose only to personnel who need to know and are bound by confidentiality.\n\n6.3 Exclusions. Excludes information that is: public, previously known, received from third parties, or independently developed.\n\n6.4 Return. Upon termination, each Party shall return the other''s Confidential Information.\n\n6.5 Defend Trade Secrets Act Notice. Pursuant to 18 U.S.C. § 1833(b), an individual shall not be held liable for disclosure of a trade secret made in confidence to a government official or attorney for reporting suspected violations of law.","type":"standard","order":6},{"id":"warranties_liability","title":"7. WARRANTIES AND LIABILITY","content":"7.1 Consultant Warranties. Consultant warrants that: (a) it has authority to enter into this Agreement; (b) Services will be performed professionally; (c) Work Product will not infringe third-party rights; and (d) it will comply with applicable laws.\n\n7.2 Client Warranties. Client warrants that it has authority to enter into this Agreement.\n\n7.3 Disclaimer. Except as stated, neither Party makes additional warranties, express or implied.\n\n7.4 Limitation of Liability. Neither Party shall be liable for indirect, consequential, or special damages. Total liability shall not exceed the fees paid or payable in the 12 months preceding the claim.\n\n7.5 Exceptions. Nothing limits liability for fraud, willful misconduct, or matters that cannot be limited by law.","type":"negotiable","order":7},{"id":"indemnification","title":"8. INDEMNIFICATION","content":"8.1 Consultant Indemnity. Consultant shall indemnify Client against third-party claims arising from: (a) Consultant''s negligence or willful misconduct; (b) Work Product infringing third-party rights (except where caused by Client materials); or (c) Consultant''s breach of this Agreement.\n\n8.2 Client Indemnity. Client shall indemnify Consultant against third-party claims arising from Client materials that infringe third-party rights.\n\n8.3 Procedure. The indemnified Party shall: (a) promptly notify the indemnifying Party; (b) allow control of the defense; and (c) provide reasonable cooperation.","type":"negotiable","order":8},{"id":"general","title":"9. GENERAL PROVISIONS","content":"9.1 Governing Law. This Agreement is governed by the laws of the State of Texas, without regard to conflict of laws principles.\n\n9.2 Venue. The Parties consent to exclusive jurisdiction of the state and federal courts in {{venue_county}} County, Texas.\n\n9.3 Notices. Notices must be in writing and delivered by hand, courier, certified mail, or email.\n\n9.4 Assignment. Neither Party may assign without consent, except to a successor in a merger or acquisition.\n\n9.5 Entire Agreement. This Agreement is the entire agreement. Amendments must be in writing signed by both Parties.\n\n9.6 Severability. Invalid provisions shall be enforced to the maximum extent permitted.\n\n9.7 Waiver. Waivers must be in writing.\n\n9.8 Force Majeure. Neither Party is liable for delays beyond reasonable control.\n\n9.9 Counterparts. May be executed in counterparts, including electronically under Texas Business and Commerce Code, Chapter 322.\n\n9.10 Non-Compete (Texas). Any non-compete provisions must comply with Texas Business and Commerce Code § 15.50.\n\n9.11 Insurance. Consultant shall maintain appropriate professional liability insurance.","type":"standard","order":9}]'::jsonb,
